// frontend/src/pages/Customers.js
import { useEffect, useMemo, useState } from "react";
import api from "../api";
import { useAuth } from "../AuthContext";

/* ===== Options ===== */
const REGION_OPTS = [
    { label: "Tất cả", value: "" },
    { label: "Miền Bắc", value: "Miền Bắc" },
    { label: "Miền Trung", value: "Miền Trung" },
    { label: "Miền Nam", value: "Miền Nam" },
];

const INDUSTRY_OPTS = [
    { label: "Tất cả", value: "" },
    { label: "CNTT / Phần mềm", value: "CNTT / Phần mềm" },
    { label: "Giáo dục", value: "Giáo dục" },
    { label: "Tài chính / Ngân hàng", value: "Tài chính / Ngân hàng" },
    { label: "Xây dựng", value: "Xây dựng" },
    { label: "Sản xuất", value: "Sản xuất" },
    { label: "Bất động sản", value: "Bất động sản" },
    { label: "Bán lẻ", value: "Bán lẻ" },
    { label: "Y tế", value: "Y tế" },
    { label: "Nông nghiệp", value: "Nông nghiệp" },
    { label: "Khác", value: "Khác" },
];

function hasAnyRole(user, allow = []) {
    if (!user) return false;
    const S = new Set();
    const add = (x) => {
        if (!x) return;
        if (Array.isArray(x)) return x.forEach(add);
        if (typeof x === "string") return S.add(x.toUpperCase());
        if (typeof x === "object")
            return ["role", "name", "authority"].forEach(
                (k) => x[k] && S.add(String(x[k]).toUpperCase())
            );
    };
    add(user?.role);
    add(user?.roles);
    add(user?.authorities);
    return allow.some((r) => S.has(r));
}

export default function Customers() {
    const { user } = useAuth();
    const canEdit = hasAnyRole(user, ["ADMIN", "SALES"]);
    const canView = hasAnyRole(user, ["ADMIN", "SALES", "ACCOUNTANT"]);

    const [rows, setRows] = useState([]);
    const [loading, setLoading] = useState(true);

    // filters
    const [q, setQ] = useState("");
    const [groupId, setGroupId] = useState("");     // nếu bạn đã có bộ lọc nhóm
    const [industry, setIndustry] = useState("");   // ✅ NEW
    const [region, setRegion] = useState("");

    // paging
    const [page, setPage] = useState(0);
    const [size] = useState(10);
    const [totalPages, setTotalPages] = useState(1);

    // groups for filter dropdown (optional)
    const [groups, setGroups] = useState([]);

    useEffect(() => {
        if (!canView) return;
        (async () => {
            try {
                // nạp danh sách nhóm cho dropdown (nếu có API)
                const { data } = await api.get("/api/customer-groups", {
                    params: { page: 0, size: 1000, sort: "name,asc" },
                });
                const list = Array.isArray(data) ? data : data?.content || [];
                setGroups(list);
            } catch {
                // bỏ qua lỗi, dropdown nhóm vẫn hoạt động với "Tất cả"
            }
        })();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [canView]);

    useEffect(() => {
        if (!canView) return;
        load();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [page, size, q, groupId, region, industry, canView]);

    async function load() {
        setLoading(true);
        try {
            const { data } = await api.get("/api/customers", {
                params: {
                    page,
                    size,
                    q: q?.trim() || undefined,
                    groupId: groupId || undefined,
                    region: region || undefined,
                    // ✅ truyền filter industry lên BE
                    industry: industry || undefined,
                },
            });
            if (Array.isArray(data)) {
                setRows(data);
                setTotalPages(1);
            } else {
                setRows(data?.content || []);
                setTotalPages(data?.totalPages ?? 1);
            }
        } catch (e) {
            console.error("Load customers failed:", e);
            setRows([]);
            setTotalPages(1);
        } finally {
            setLoading(false);
        }
    }

    const groupMap = useMemo(() => {
        const m = new Map();
        groups.forEach((g) => m.set(String(g.id), g));
        return m;
    }, [groups]);

    function onSearchKey(e) {
        if (e.key === "Enter") {
            setPage(0);
            load();
        }
    }

    function goPrev() {
        setPage((p) => Math.max(0, p - 1));
    }
    function goNext() {
        setPage((p) => Math.min(totalPages - 1, p + 1));
    }

    if (!canView) {
        return (
            <div className="space-y-2">
                <h2 className="text-lg font-semibold">Khách hàng</h2>
                <p className="text-sm text-slate-500">Bạn không có quyền xem trang này.</p>
            </div>
        );
    }

    return (
        <div className="space-y-5">
            {/* Header & filters */}
            <div className="flex flex-wrap items-center justify-between gap-3">
                <div>
                    <h2 className="text-lg font-semibold">Khách hàng</h2>
                    <p className="text-sm text-slate-500">
                        Quản lý thông tin khách hàng & phân nhóm
                    </p>
                </div>

                <div className="flex flex-wrap items-center gap-2">
                    {/* search */}
                    <input
                        value={q}
                        onChange={(e) => setQ(e.target.value)}
                        onKeyDown={onSearchKey}
                        placeholder="Tên/Email/SDT/Địa chỉ..."
                        className="w-72 px-3 py-2 rounded-xl border border-indigo-100 bg-white shadow"
                    />

                    {/* group filter (optional) */}
                    <div className="flex items-center gap-2">
                        <span className="text-sm text-slate-500">Nhóm</span>
                        <select
                            value={groupId}
                            onChange={(e) => {
                                setGroupId(e.target.value);
                                setPage(0);
                            }}
                            className="px-3 py-2 rounded-xl border border-indigo-100 bg-white shadow min-w-[140px]"
                        >
                            <option value="">Tất cả</option>
                            {groups.map((g) => (
                                <option key={g.id} value={g.id}>
                                    {g.name}
                                </option>
                            ))}
                        </select>
                    </div>

                    {/* ✅ NEW: industry filter */}
                    <div className="flex items-center gap-2">
                        <span className="text-sm text-slate-500">Ngành</span>
                        <select
                            value={industry}
                            onChange={(e) => {
                                setIndustry(e.target.value);
                                setPage(0);
                            }}
                            className="px-3 py-2 rounded-xl border border-indigo-100 bg-white shadow min-w-[160px]"
                        >
                            {INDUSTRY_OPTS.map((o) => (
                                <option key={o.value} value={o.value}>
                                    {o.label}
                                </option>
                            ))}
                        </select>
                    </div>

                    {/* region filter */}
                    <div className="flex items-center gap-2">
                        <span className="text-sm text-slate-500">Khu vực</span>
                        <select
                            value={region}
                            onChange={(e) => {
                                setRegion(e.target.value);
                                setPage(0);
                            }}
                            className="px-3 py-2 rounded-xl border border-indigo-100 bg-white shadow min-w-[140px]"
                        >
                            {REGION_OPTS.map((o) => (
                                <option key={o.value} value={o.value}>
                                    {o.label}
                                </option>
                            ))}
                        </select>
                    </div>

                    {canEdit && (
                        <button
                            onClick={() => (window.location.href = "/customers/new")}
                            className="px-3 py-2 rounded-xl bg-indigo-600 text-white hover:bg-indigo-700"
                        >
                            Thêm khách hàng
                        </button>
                    )}
                </div>
            </div>

            {/* Table */}
            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Tên</th>
                            <th className="px-4 py-3 text-left">Nhóm</th>
                            <th className="px-4 py-3 text-left">Khu vực</th>
                            <th className="px-4 py-3 text-left">Điện thoại</th>
                            <th className="px-4 py-3 text-left">Email</th>
                            <th className="px-4 py-3 text-left">Địa chỉ</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={7}>
                                    Đang tải…
                                </td>
                            </tr>
                        ) : rows.length === 0 ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={7}>
                                    Không có dữ liệu
                                </td>
                            </tr>
                        ) : (
                            rows.map((c) => {
                                const groupName =
                                    c.group?.name ||
                                    (c.groupName ?? "") ||
                                    (c.groupId ? `#${c.groupId}` : "");
                                return (
                                    <tr key={c.id} className="hover:bg-indigo-50/40">
                                        <td className="px-4 py-3">
                                            <a
                                                href={`/customers/${c.id}`}
                                                className="text-indigo-600 hover:underline"
                                            >
                                                {c.name}
                                            </a>
                                        </td>
                                        <td className="px-4 py-3">{groupName}</td>
                                        <td className="px-4 py-3">{c.region || "-"}</td>
                                        <td className="px-4 py-3">{c.phone || "-"}</td>
                                        <td className="px-4 py-3">{c.email || "-"}</td>
                                        <td className="px-4 py-3">{c.address || "-"}</td>
                                        <td className="px-4 py-3 text-right">
                                            <div className="inline-flex gap-2">
                                                {canEdit && (
                                                    <a
                                                        href={`/customers/${c.id}/edit`}
                                                        className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100"
                                                    >
                                                        Sửa
                                                    </a>
                                                )}
                                                {canEdit && (
                                                    <button
                                                        className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                                        onClick={async () => {
                                                            if (
                                                                !window.confirm(
                                                                    `Xoá khách hàng "${c.name}"? Hành động không thể hoàn tác.`
                                                                )
                                                            )
                                                                return;
                                                            try {
                                                                await api.delete(`/api/customers/${c.id}`);
                                                                load();
                                                            } catch (e) {
                                                                alert("Xoá thất bại");
                                                            }
                                                        }}
                                                    >
                                                        Xóa
                                                    </button>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                );
                            })
                        )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Pagination */}
            <div className="flex items-center gap-3">
                <button
                    className="px-3 py-1 rounded bg-slate-100 hover:bg-slate-200 disabled:opacity-50"
                    onClick={goPrev}
                    disabled={page <= 0}
                >
                    ← Trước
                </button>
                <div className="text-sm text-slate-600">
                    Trang {totalPages ? page + 1 : 0}/{totalPages}
                </div>
                <button
                    className="px-3 py-1 rounded bg-slate-100 hover:bg-slate-200 disabled:opacity-50"
                    onClick={goNext}
                    disabled={page >= totalPages - 1}
                >
                    Sau →
                </button>
            </div>
        </div>
    );
}
